// fetch-candidates — list open issues and partition them for the pipeline.
//
// Emits { unclassifiedCount, unclassified[] } where `unclassified` is the set
// of issues that need an LLM triage pass this tick:
//   - brand-new issues carrying no `fullstack:` verdict/lifecycle label
//   - `fullstack:manual` issues edited since they were declined (re-judge-on-edit)
//   - stale `fullstack:in-progress` leases (older than LEASE_TTL_HOURS, no PR) —
//     the lease is released here and the issue re-enters triage (self-heal)
//
// Already-classified actionable issues (`fullstack:go` / `fullstack:needs-approval`)
// are NOT re-analysed — `select` picks them by their stored labels. That is the
// whole point of persisting the verdict: triage's LLM only ever looks once.
//
// ESCAPE HATCH: set FULLSTACK_REASSIGN=true (default off) to force a re-judge of
// every issue carrying only a verdict/needs-info label (go / needs-approval /
// manual / needs-info) — it re-enters triage and apply-verdicts overwrites the
// stored verdict. In-flight/human-owned states (in-progress lease, pr-open,
// awaiting-human) are always protected. Because this reads a workflow-global env
// ref, it re-judges the backlog on EVERY tick while enabled — flip it on, let the
// backlog drain over a few ticks (see the batch cap below), then flip it off.
//
// BATCH CAP: triage now clones `main` and verifies each issue against the code,
// so a batch of ~90 backlog issues cannot be judged reliably in one agent call.
// TRIAGE_BATCH_MAX (default 25) caps how many issues are handed to triage per
// tick; the rest carry no verdict and are picked up on the next tick. A big
// reassign backlog therefore drains over several ticks instead of one impossible
// mega-call — steady-state (a handful of new issues) is unaffected.
//
// Reads:  /output/input.json (unused — cron tick), env GITHUB_TOKEN, FULLSTACK_REPO,
//         LEASE_TTL_HOURS, MAX_ATTEMPTS, FULLSTACK_REASSIGN, TRIAGE_BATCH_MAX
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

export const VERDICT_LABELS = ['fullstack:go', 'fullstack:needs-approval', 'fullstack:manual'];
export const LIFECYCLE_LABELS = ['fullstack:in-progress', 'fullstack:awaiting-human', 'fullstack:pr-open', 'fullstack:needs-info'];
const IN_PROGRESS = 'fullstack:in-progress';
const MANUAL = 'fullstack:manual';
const PR_OPEN = 'fullstack:pr-open';
const NEEDS_INFO = 'fullstack:needs-info';
const AWAITING_HUMAN = 'fullstack:awaiting-human';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const LEASE_TTL_HOURS = Number(process.env.LEASE_TTL_HOURS || '2');
const MAX_ATTEMPTS = Number(process.env.MAX_ATTEMPTS || '3');
const REASSIGN = /^\s*(true|1|yes|on)\s*$/i.test(process.env.FULLSTACK_REASSIGN || '');
const TRIAGE_BATCH_MAX = Number(process.env.TRIAGE_BATCH_MAX || '25');

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok) throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  return res.status === 204 ? null : res.json();
}

export function labelNames(issue) {
  return (issue.labels || []).map((l) => (typeof l === 'string' ? l : l.name));
}

/** Newest created_at of a `labeled <name>` event, and how many such events exist. */
export function summariseLabelEvents(events, name) {
  let latest = null;
  let count = 0;
  for (const e of events) {
    if (e.event === 'labeled' && e.label && e.label.name === name) {
      count += 1;
      if (!latest || new Date(e.created_at).getTime() > new Date(latest).getTime()) latest = e.created_at;
    }
  }
  return { latestAt: latest, count };
}

/** Decide what to do with one issue given its labels + events. Pure.
 *  `reassign === true` forces a re-judge of already-verdicted / parked issues. */
export function classifyIssue(issue, events, nowMs, ttlHours, maxAttempts, reassign) {
  const labels = labelNames(issue);
  const has = (l) => labels.includes(l);

  // Always protected: an open PR or an open human gate is in-flight work that a
  // reassign must never yank back into triage.
  if (has(PR_OPEN) || has(AWAITING_HUMAN)) return { action: 'skip' };

  const attempts = summariseLabelEvents(events, IN_PROGRESS).count;

  // An active lease is live implementation work; reassign does not interrupt it
  // (only the stale-lease self-heal reclaims, exactly as before).
  if (has(IN_PROGRESS)) {
    const { latestAt } = summariseLabelEvents(events, IN_PROGRESS);
    const ageHours = latestAt ? (nowMs - new Date(latestAt).getTime()) / 3_600_000 : Infinity;
    if (ageHours > ttlHours) return { action: 'reclaim', attemptCount: attempts };
    return { action: 'skip' };
  }

  // Parked for a human. Reassign re-opens it: strip needs-info (a lifecycle label
  // apply-verdicts does not manage), then re-triage.
  if (has(NEEDS_INFO)) {
    if (reassign === true) return { action: 'reopen', attemptCount: attempts };
    return { action: 'skip' };
  }

  if (has(MANUAL)) {
    const { latestAt } = summariseLabelEvents(events, MANUAL);
    // apply-verdicts posts the decline comment ~1s after adding the manual label, which bumps updated_at past the labeled event; ignore that self-write and only re-triage on a genuine later human edit.
    const SELF_DECLINE_GRACE_MS = 120_000;
    const editedSince = latestAt && new Date(issue.updated_at).getTime() - new Date(latestAt).getTime() > SELF_DECLINE_GRACE_MS;
    if (reassign === true || editedSince) return { action: 'triage', attemptCount: attempts };
    return { action: 'skip' };
  }

  if (has('fullstack:go') || has('fullstack:needs-approval')) {
    if (reassign === true) return { action: 'triage', attemptCount: attempts };
    return { action: 'skip' };
  }

  // No fullstack label at all → brand-new, needs triage.
  return { action: 'triage', attemptCount: attempts };
}

export function toCandidate(issue, attemptCount, maxAttempts) {
  return {
    number: issue.number,
    title: issue.title,
    body: (issue.body || '').slice(0, 4000),
    url: issue.html_url,
    author: (issue.user && issue.user.login) || null,
    labels: labelNames(issue),
    attemptCount,
    poison: attemptCount >= maxAttempts,
    createdAt: issue.created_at,
    updatedAt: issue.updated_at,
  };
}

async function main() {
  const collected = [];
  for (let page = 1; page <= 5; page++) {
    const batch = await gh(`/repos/${REPO}/issues?state=open&per_page=100&page=${page}`);
    for (const i of batch) {
      if (i.pull_request) continue; // issues endpoint returns PRs too
      if (i.assignee) continue; // a human is on it
      collected.push(i);
    }
    if (batch.length < 100) break;
  }

  const nowMs = Date.now();
  const unclassified = [];
  for (const issue of collected) {
    const labels = labelNames(issue);
    const touchesLifecycleOrManual = labels.includes(IN_PROGRESS) || labels.includes(MANUAL);
    // Only issues wearing in-progress / manual need the (rate-limited) events call.
    const events = touchesLifecycleOrManual
      ? await gh(`/repos/${REPO}/issues/${issue.number}/events?per_page=100`)
      : [];
    const decision = classifyIssue(issue, events, nowMs, LEASE_TTL_HOURS, MAX_ATTEMPTS, REASSIGN);

    if (decision.action === 'reclaim') {
      // Release the expired lease so the issue re-enters triage.
      await gh(`/repos/${REPO}/issues/${issue.number}/labels/${encodeURIComponent(IN_PROGRESS)}`, { method: 'DELETE' })
        .catch((err) => console.error(`reclaim: failed to drop lease on #${issue.number}: ${err.message}`));
      unclassified.push(toCandidate(issue, decision.attemptCount, MAX_ATTEMPTS));
    } else if (decision.action === 'reopen') {
      // Reassign re-opens a parked issue: drop needs-info so apply-verdicts can
      // write a fresh verdict without select's needs-info block stranding it.
      await gh(`/repos/${REPO}/issues/${issue.number}/labels/${encodeURIComponent(NEEDS_INFO)}`, { method: 'DELETE' })
        .catch((err) => console.error(`reopen: failed to drop needs-info on #${issue.number}: ${err.message}`));
      unclassified.push(toCandidate(issue, decision.attemptCount, MAX_ATTEMPTS));
    } else if (decision.action === 'triage') {
      unclassified.push(toCandidate(issue, decision.attemptCount, MAX_ATTEMPTS));
    }
  }

  if (REASSIGN) console.log('fetch-candidates: FULLSTACK_REASSIGN=on — re-judging already-classified issues this tick');

  // Cap the batch so triage can clone + verify each issue reliably in one pass.
  // The overflow carries no verdict, so it is re-collected next tick (self-drains).
  const deferred = unclassified.length - TRIAGE_BATCH_MAX;
  const batch = unclassified.slice(0, TRIAGE_BATCH_MAX);
  if (deferred > 0) console.log(`fetch-candidates: capped batch at ${TRIAGE_BATCH_MAX}; ${deferred} issue(s) deferred to a later tick`);

  writeFileSync('/output/result.json', JSON.stringify({ unclassifiedCount: batch.length, unclassified: batch }));
  console.log(`fetch-candidates: ${batch.length} issue(s) to triage: ${batch.map((x) => '#' + x.number).join(', ') || '(none)'}`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('fetch-candidates crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// apply-verdicts — persist triage's batch judgment as labels.
//
// For each verdict, reconcile the issue's `fullstack:` labels to the desired
// { suitability, priority } and (once, on the transition INTO manual) post a
// gracious decline comment. An `obsolete` verdict is closed here in the same
// batch pass: label + a comment to the author with triage's evidence + a
// reversible close. Best-effort per issue: a failed write logs and continues,
// leaving that issue unclassified for the next tick to re-triage.
//
// Reads:  /output/input.json (steps.triage.verdicts), env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const SUITABILITY = {
  go: 'fullstack:go',
  'needs-approval': 'fullstack:needs-approval',
  manual: 'fullstack:manual',
  obsolete: 'fullstack:obsolete',
};
const ACTIONABLE = new Set(['go', 'needs-approval']);
const ALL_SUITABILITY = Object.values(SUITABILITY);
const ALL_PRIO = ['fullstack:prio-high', 'fullstack:prio-med', 'fullstack:prio-low'];
const PRIO = { high: 'fullstack:prio-high', med: 'fullstack:prio-med', low: 'fullstack:prio-low' };

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

/** Given current labels + a verdict, compute labels to add / remove. Pure. */
export function reconcile(currentLabels, verdict) {
  const want = new Set();
  const suit = SUITABILITY[verdict.suitability];
  if (suit) want.add(suit);
  if (ACTIONABLE.has(verdict.suitability) && PRIO[verdict.priority]) want.add(PRIO[verdict.priority]);

  const managed = [...ALL_SUITABILITY, ...ALL_PRIO];
  const add = [...want].filter((l) => !currentLabels.includes(l));
  const remove = managed.filter((l) => currentLabels.includes(l) && !want.has(l));
  const newlyManual = verdict.suitability === 'manual' && !currentLabels.includes(SUITABILITY.manual);
  return { add, remove, newlyManual };
}

function declineComment(verdict) {
  const reason = verdict.reason || 'this needs product/domain judgement an autonomous agent should not make.';
  return `🤖 **mediforce-fullstack**: leaving this one for a human — ${reason}\n\n` +
    'Add the `fullstack:go` label if you\'d like me to attempt it anyway.';
}

// `not_planned` for a removed/migrated subsystem; `completed` when a fix already
// shipped (already-fixed) — mirrors mark-fixed's "completed" close.
export function closeReason(category) {
  return category === 'already-fixed' ? 'completed' : 'not_planned';
}

function obsoleteComment(verdict, author) {
  const reason = verdict.reason || 'the code it describes has changed';
  const evidence = verdict.evidence ? ` (${verdict.evidence})` : '';
  const cc = author ? `@${author} ` : '';
  return `${cc}🤖 **mediforce-fullstack**: closing as no longer applicable — ${reason}${evidence}. ` +
    'Reopen if I\'ve got this wrong.';
}

async function applyOne(verdict) {
  const issue = await gh(`/repos/${REPO}/issues/${verdict.issueNumber}`);
  const current = (issue.labels || []).map((l) => (typeof l === 'string' ? l : l.name));
  const { add, remove, newlyManual } = reconcile(current, verdict);

  if (add.length > 0) {
    await gh(`/repos/${REPO}/issues/${verdict.issueNumber}/labels`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ labels: add }),
    });
  }
  for (const name of remove) {
    await gh(`/repos/${REPO}/issues/${verdict.issueNumber}/labels/${encodeURIComponent(name)}`, { method: 'DELETE' });
  }
  if (newlyManual) {
    await gh(`/repos/${REPO}/issues/${verdict.issueNumber}/comments`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: declineComment(verdict) }),
    });
  }

  let closed = false;
  if (verdict.suitability === 'obsolete') {
    const author = (issue.user && issue.user.login) || null;
    await gh(`/repos/${REPO}/issues/${verdict.issueNumber}/comments`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: obsoleteComment(verdict, author) }),
    });
    await gh(`/repos/${REPO}/issues/${verdict.issueNumber}`, {
      method: 'PATCH',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ state: 'closed', state_reason: closeReason(verdict.category) }),
    });
    closed = true;
  }
  return { issueNumber: verdict.issueNumber, add, remove, newlyManual, closed };
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const verdicts = input?.steps?.triage?.verdicts || [];
  const results = [];
  for (const v of verdicts) {
    if (!v || !v.issueNumber || !SUITABILITY[v.suitability]) {
      console.error(`apply-verdicts: skipping malformed verdict ${JSON.stringify(v)}`);
      continue;
    }
    // Never auto-close on an unproven obsolete verdict — downgrade to manual so a
    // human sees it instead of it vanishing without evidence.
    if (v.suitability === 'obsolete' && !v.evidence) {
      console.error(`apply-verdicts: #${v.issueNumber} obsolete without evidence — downgrading to manual`);
      v.suitability = 'manual';
      v.reason = `flagged possibly obsolete but without concrete evidence — ${v.reason || 'needs a human to confirm'}`;
    }
    try {
      results.push(await applyOne(v));
    } catch (err) {
      console.error(`apply-verdicts: #${v.issueNumber} failed (will re-triage next tick): ${err.message}`);
    }
  }
  const closedCount = results.filter((r) => r.closed === true).length;
  writeFileSync('/output/result.json', JSON.stringify({ applied: results.length, closed: closedCount, results }));
  console.log(`apply-verdicts: labelled ${results.length}/${verdicts.length} issue(s), closed ${closedCount} as obsolete`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('apply-verdicts crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// select — deterministically pick the next issue to work.
//
// Fresh label-filtered query for the actionable pool (`fullstack:go` +
// `fullstack:needs-approval`), so it sees whatever `apply-verdicts` just wrote.
// No LLM here — this is the "don't re-analyse the backlog" payoff. Sort by
// priority (high>med>low) then oldest (FIFO fairness), pick one.
//
// Reads:  env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json → { selected, issueNumber, suitability, priority, title, body, url, author }

import { writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const BLOCKED = ['fullstack:in-progress', 'fullstack:awaiting-human', 'fullstack:pr-open', 'fullstack:needs-info'];
const PRIO_RANK = { 'fullstack:prio-high': 0, 'fullstack:prio-med': 1, 'fullstack:prio-low': 2 };

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders() });
  if (!res.ok) throw new Error(`GitHub ${res.status} ${path}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

function labelNames(issue) {
  return (issue.labels || []).map((l) => (typeof l === 'string' ? l : l.name));
}

export function priorityOf(labels) {
  if (labels.includes('fullstack:prio-high')) return 'high';
  if (labels.includes('fullstack:prio-med')) return 'med';
  return 'low';
}

export function priorityRank(labels) {
  for (const [label, rank] of Object.entries(PRIO_RANK)) if (labels.includes(label)) return rank;
  return 3;
}

/** Sort actionable issues: priority asc (high first), then oldest first. Pure. */
export function rankCandidates(issues) {
  return [...issues].sort((a, b) => {
    const la = labelNames(a);
    const lb = labelNames(b);
    return priorityRank(la) - priorityRank(lb) ||
      new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
  });
}

export function isActionable(issue) {
  const labels = labelNames(issue);
  if (BLOCKED.some((l) => labels.includes(l))) return false;
  if (issue.assignee) return false;
  return true;
}

async function main() {
  const pool = new Map();
  for (const label of ['fullstack:go', 'fullstack:needs-approval']) {
    const issues = await gh(`/repos/${REPO}/issues?state=open&labels=${encodeURIComponent(label)}&per_page=100`);
    for (const i of issues) {
      if (i.pull_request) continue;
      if (!isActionable(i)) continue;
      pool.set(i.number, i);
    }
  }

  const ranked = rankCandidates([...pool.values()]);
  if (ranked.length === 0) {
    writeFileSync('/output/result.json', JSON.stringify({ selected: false }));
    console.log('select: nothing actionable this tick');
    return;
  }

  const chosen = ranked[0];
  const labels = labelNames(chosen);
  const suitability = labels.includes('fullstack:go') ? 'go' : 'needs-approval';
  const result = {
    selected: true,
    issueNumber: chosen.number,
    suitability,
    priority: priorityOf(labels),
    title: chosen.title,
    body: (chosen.body || '').slice(0, 4000),
    url: chosen.html_url,
    author: (chosen.user && chosen.user.login) || null,
  };
  writeFileSync('/output/result.json', JSON.stringify(result));
  console.log(`select: #${chosen.number} (${suitability}, ${result.priority})`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('select crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// claim — set the `fullstack:in-progress` lease on the selected issue.
//
// Runs on both entry points into `implement`: the go path (from `select`) and
// the gate-approval path (from `clarify-approve`). Either way `select` ran, so
// the issue number is at input.steps.select.issueNumber.
//
// FAILS HARD: if we cannot set the lease we must NOT let `implement` proceed on
// an unclaimed issue (that invites duplicate work). A hard failure just means
// the next tick re-selects it. Scripts ignore `continueOnError` anyway.
//
// Reads:  /output/input.json, env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const IN_PROGRESS = 'fullstack:in-progress';
const DROP = ['fullstack:go', 'fullstack:awaiting-human'];

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  // Removing a label that isn't present returns 404 — that's fine, treat as no-op.
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const issueNumber = input?.steps?.select?.issueNumber;
  if (!issueNumber) throw new Error('claim: no select.issueNumber in step input');

  await gh(`/repos/${REPO}/issues/${issueNumber}/labels`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ labels: [IN_PROGRESS] }),
  });
  for (const name of DROP) {
    await gh(`/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(name)}`, { method: 'DELETE' });
  }

  writeFileSync('/output/result.json', JSON.stringify({ issueNumber, claimed: true }));
  console.log(`claim: leased #${issueNumber}`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('claim crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// notify-gate — resolve the reviewer, ping GitHub, hand the issue to a human.
//
// Reviewer selection (tiered, per FULLSTACK_REVIEWER_MAP {githubLogin: email/uid}):
//   1. creator's login IS in the map  -> assign the creator (they own the issue)
//   2. creator's login is NOT in the map (external / non-dev) -> assign the
//      fallback admin, cc BOTH: the creator (fyi) + the admin (pick up)
// FULLSTACK_DEFAULT_ADMIN is the admin's GitHub LOGIN (which MUST be a key in the
// map); their Mediforce id for assignedTo is looked up from the map, and the same
// login is the cc handle — so there is one admin value, not two.
// `reviewerId` is emitted for clarify-approve.assignedTo="${steps.notify-gate.reviewerId}".
//
// Ordering is deliberate: relabel FIRST (needs-approval -> awaiting-human) so the
// issue leaves the selectable pool even if the comment fails; the comment is
// best-effort (it is the only human notification — the platform does not push
// task_assigned — but a missing ping must not strand the relabel).
//
// Reads:  /output/input.json (steps.select, steps.draft-plan), env GITHUB_TOKEN,
//         FULLSTACK_REPO, FULLSTACK_REVIEWER_MAP, FULLSTACK_DEFAULT_ADMIN, APP_BASE_URL
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const NEEDS_APPROVAL = 'fullstack:needs-approval';
const AWAITING_HUMAN = 'fullstack:awaiting-human';

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

/** Resolve reviewer from the map. `adminLogin` is a GitHub login that must be a
 *  key in the map; the map yields its Mediforce id. Pure. */
export function resolveReviewer(creatorLogin, reviewerMap, adminLogin) {
  if (creatorLogin && Object.prototype.hasOwnProperty.call(reviewerMap, creatorLogin)) {
    return { reviewerId: reviewerMap[creatorLogin], reviewerGh: creatorLogin, reviewerIsCreator: true };
  }
  const reviewerId = adminLogin && Object.prototype.hasOwnProperty.call(reviewerMap, adminLogin)
    ? reviewerMap[adminLogin]
    : null;
  return { reviewerId, reviewerGh: adminLogin || null, reviewerIsCreator: false };
}

/** Build the gate comment. Pure. */
export function buildGateComment(plan, questions, appBaseUrl, creatorLogin, resolved) {
  const qlist = (questions || []).map((q) => `- ${q}`).join('\n') || '- (none — confirm the plan)';
  const lines = [
    '🤖 **mediforce-fullstack** wants to attempt this issue, but needs a human sign-off first.',
    '',
    `**Proposed plan:** ${plan || '(see questions)'}`,
    '',
    '**Questions:**',
    qlist,
    '',
    `Review and answer in Mediforce → **Human actions**: ${appBaseUrl || '(APP_BASE_URL not set)'}`,
    '',
  ];
  if (resolved.reviewerIsCreator) {
    lines.push(`cc @${creatorLogin} — you raised this, so it's assigned to you to approve.`);
  } else {
    if (creatorLogin) lines.push(`cc @${creatorLogin} — your issue is being processed.`);
    if (resolved.reviewerGh) {
      lines.push(`cc @${resolved.reviewerGh} — the reporter has no Mediforce account; please pick this up via the link above.`);
    }
  }
  return lines.join('\n');
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const select = input?.steps?.select || {};
  const plan = input?.steps?.['draft-plan'] || {};
  const issueNumber = select.issueNumber;
  if (!issueNumber) throw new Error('notify-gate: no select.issueNumber');

  let reviewerMap = {};
  try {
    reviewerMap = JSON.parse(process.env.FULLSTACK_REVIEWER_MAP || '{}');
  } catch (err) {
    console.error(`notify-gate: FULLSTACK_REVIEWER_MAP is not valid JSON: ${err.message}`);
  }
  const resolved = resolveReviewer(select.author, reviewerMap, process.env.FULLSTACK_DEFAULT_ADMIN);
  if (!resolved.reviewerId) {
    console.error('notify-gate: empty reviewer id — is FULLSTACK_DEFAULT_ADMIN a key in FULLSTACK_REVIEWER_MAP? assignedTo would fall back to the run creator (a cron phantom).');
  }

  // 1. Relabel first (hard) — removes the issue from the selectable pool.
  await gh(`/repos/${REPO}/issues/${issueNumber}/labels`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ labels: [AWAITING_HUMAN] }),
  });
  await gh(`/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(NEEDS_APPROVAL)}`, { method: 'DELETE' });

  // 2. Comment (best-effort) — the actual human ping.
  let commented = false;
  try {
    await gh(`/repos/${REPO}/issues/${issueNumber}/comments`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: buildGateComment(plan.planSummary, plan.questions, process.env.APP_BASE_URL, select.author, resolved) }),
    });
    commented = true;
  } catch (err) {
    console.error(`notify-gate: comment failed (task still created): ${err.message}`);
  }

  writeFileSync('/output/result.json', JSON.stringify({
    issueNumber,
    reviewerId: resolved.reviewerId,
    reviewerIsCreator: resolved.reviewerIsCreator,
    creatorLogin: select.author,
    commented,
  }));
  console.log(`notify-gate: #${issueNumber} → ${resolved.reviewerIsCreator ? 'creator' : 'admin'} (${resolved.reviewerId})`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('notify-gate crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// publish — open (or refresh) the PR for the reviewed change, then relabel.
//
// Assembles the PR body from AGENT-authored text (implement.prBody, the
// revise log, self-review concerns) — this script writes NO prose, it only
// concatenates and templates. Draft-vs-ready is decided by the final review
// state:
//   ship               -> ready-for-review, clean
//   flag               -> ready-for-review, FYI notes appended
//   capped revise       -> DRAFT, "must fix before merge" notes appended
//
// Idempotent: reuses an existing open PR for the branch instead of erroring.
//
// Reads:  /output/input.json (steps.implement, steps.self-review, steps.revise),
//         env GITHUB_TOKEN, FULLSTACK_REPO, REVIEW_MAX
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const [OWNER, NAME] = REPO.split('/');
const REVIEW_MAX = Number(process.env.REVIEW_MAX || '2');
const IN_PROGRESS = 'fullstack:in-progress';
const PR_OPEN = 'fullstack:pr-open';

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

/** Decide draft flag + which notes heading applies. Pure. */
export function reviewOutcome(selfReview, reviewCount, reviewMax) {
  const verdict = selfReview?.verdict;
  const capped = verdict === 'revise' && (reviewCount ?? 0) >= reviewMax;
  if (capped) return { draft: true, heading: '### ⚠️ Must fix before merge' };
  if (verdict === 'flag') return { draft: false, heading: '### 🤖 self-review notes (FYI)' };
  return { draft: false, heading: null };
}

/** Assemble the PR body from agent-written pieces. Pure. */
export function buildPrBody(implement, selfReview, revise, outcome) {
  const parts = [implement.prBody || implement.summary || ''];
  const log = revise?.reviseLog;
  if (Array.isArray(log) && log.length > 0) {
    parts.push('### 🔁 Review & revision history', log.map((l) => `- ${l}`).join('\n'));
  }
  const concerns = selfReview?.concerns;
  if (outcome.heading && Array.isArray(concerns) && concerns.length > 0) {
    parts.push(outcome.heading, concerns.map((c) => `- ${c}`).join('\n'));
  }
  parts.push('---', '🤖 generated by mediforce-fullstack');
  return parts.filter(Boolean).join('\n\n');
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const implement = input?.steps?.implement || {};
  const selfReview = input?.steps?.['self-review'] || {};
  const revise = input?.steps?.revise || {};
  const issueNumber = implement.issueNumber;
  const branch = implement.branch;
  const baseBranch = implement.baseBranch || 'main';
  if (!issueNumber || !branch) throw new Error('publish: missing implement.issueNumber or implement.branch');

  const outcome = reviewOutcome(selfReview, revise.reviewCount, REVIEW_MAX);
  const body = buildPrBody(implement, selfReview, revise, outcome);

  const existing = await gh(`/repos/${REPO}/pulls?head=${OWNER}:${encodeURIComponent(branch)}&state=open`);
  let pr;
  if (Array.isArray(existing) && existing.length > 0) {
    pr = await gh(`/repos/${REPO}/pulls/${existing[0].number}`, {
      method: 'PATCH',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body }),
    });
  } else {
    pr = await gh(`/repos/${REPO}/pulls`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: implement.prTitle, head: branch, base: baseBranch, body, draft: outcome.draft }),
    });
  }

  // Swap the lease for the done-state label, then comment the link.
  await gh(`/repos/${REPO}/issues/${issueNumber}/labels`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ labels: [PR_OPEN] }),
  });
  await gh(`/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(IN_PROGRESS)}`, { method: 'DELETE' });
  await gh(`/repos/${REPO}/issues/${issueNumber}/comments`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ body: `🤖 Opened ${outcome.draft ? 'draft ' : ''}PR ${pr.html_url} for this issue. — mediforce-fullstack` }),
  }).catch((err) => console.error(`publish: link comment failed: ${err.message}`));

  writeFileSync('/output/result.json', JSON.stringify({ issueNumber, prUrl: pr.html_url, prNumber: pr.number, branch, draft: outcome.draft }));
  console.log(`publish: #${issueNumber} → ${outcome.draft ? 'draft ' : ''}PR ${pr.html_url}`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('publish crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// arm-timer — compute the CI-poll deadline for the next `wait-ci` pause.
//
// The `wait` action reads `config.duration.{minutes}` as raw NUMBERS and does
// NOT interpolate them, so a secret-driven wait length must go through the
// interpolatable `deadline` field instead. This step reads CI_WAIT_MINUTES
// (secret-backed env, changeable without re-registering) and emits an absolute
// ISO deadline that `wait-ci` consumes as `${steps.arm-timer.deadline}`.
//
// It sits in the CI loop and re-arms on every iteration (publish -> here, and
// after each fix / pending re-poll), so each pause gets a fresh future deadline
// — a single up-front computation would go stale on the 2nd lap.
//
// Reads:  env CI_WAIT_MINUTES (default 15)
// Writes: /output/result.json -> { deadline, waitMinutes }

import { writeFileSync } from 'node:fs';

const DEFAULT_MINUTES = 15;

/** Parse the configured wait length, falling back to the default for an unset /
 *  unresolved / non-positive value. Pure. */
export function resolveWaitMinutes(raw) {
  const n = Number(raw);
  return Number.isFinite(n) && n > 0 ? n : DEFAULT_MINUTES;
}

function main() {
  const waitMinutes = resolveWaitMinutes(process.env.CI_WAIT_MINUTES);
  const deadline = new Date(Date.now() + waitMinutes * 60_000).toISOString();
  writeFileSync('/output/result.json', JSON.stringify({ deadline, waitMinutes }));
  console.log(`arm-timer: next CI check at ${deadline} (in ${waitMinutes} min)`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main();
}

// check-ci — read the PR's CI result and ROUTE the loop.
//
// This is the decision node of the CI-fix loop. Transition expressions cannot
// read env/secrets (the evaluator only sees output/variables/verdict), so the
// caps live HERE in JS where `process.env` is readable, and the step emits a
// single `nextAction` the transitions switch on:
//
//   green  -> CI passed                              -> mark-ci-green
//   fix    -> CI failed  and ciRound   < CI_FIX_MAX  -> fix-after-tests
//   wait   -> CI pending and pollCount < CI_POLL_MAX -> arm-timer (re-poll)
//   giveup -> caps exhausted (failed or stuck)       -> mark-ci-failed
//
// The container cannot `pnpm install` to reproduce a failure, so the whole
// point of this step is to HARVEST the real error text from GitHub — failing
// check names, their output summary, and their annotations (file:line:message)
// — and hand it to `fix-after-tests`, which fixes statically from that. CI is
// the reproduction environment; this step is the eyes.
//
// Reads:  /output/input.json (steps.publish, steps.fix-after-tests, steps.check-ci),
//         env GITHUB_TOKEN, FULLSTACK_REPO, CI_FIX_MAX, CI_POLL_MAX
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const CI_FIX_MAX = Number(process.env.CI_FIX_MAX) > 0 ? Number(process.env.CI_FIX_MAX) : 3;
const CI_POLL_MAX = Number(process.env.CI_POLL_MAX) > 0 ? Number(process.env.CI_POLL_MAX) : 4;
const FAILED_CONCLUSIONS = ['failure', 'timed_out', 'cancelled', 'action_required', 'stale'];

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders() });
  if (!res.ok) throw new Error(`GitHub ${res.status} ${path}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

/** Collapse the check-runs list into one raw CI state. Pure.
 *  - no runs yet or any run still running -> 'pending'
 *  - any completed run with a failing conclusion -> 'failed'
 *  - all completed and none failing -> 'passed' */
export function classifyRuns(runs) {
  if (!Array.isArray(runs) || runs.length === 0) return 'pending';
  const failing = runs.filter((r) => r.status === 'completed' && FAILED_CONCLUSIONS.includes(r.conclusion));
  if (failing.length > 0) return 'failed';
  const running = runs.filter((r) => r.status !== 'completed');
  if (running.length > 0) return 'pending';
  return 'passed';
}

/** Route from raw state + counters + caps. Pure. */
export function decideNextAction(raw, ciRound, pollCount, ciFixMax, ciPollMax) {
  if (raw === 'passed') return 'green';
  if (raw === 'failed') return ciRound < ciFixMax ? 'fix' : 'giveup';
  return pollCount < ciPollMax ? 'wait' : 'giveup';
}

/** Trim an annotation list down to what an agent needs to locate the error. Pure. */
export function summariseAnnotations(annotations) {
  return (annotations || []).slice(0, 20).map((a) => ({
    path: a.path,
    startLine: a.start_line,
    endLine: a.end_line,
    level: a.annotation_level,
    message: (a.message || '').slice(0, 600),
  }));
}

async function collectFailing(runs) {
  const failing = runs.filter((r) => r.status === 'completed' && FAILED_CONCLUSIONS.includes(r.conclusion));
  const out = [];
  for (const run of failing) {
    let annotations = [];
    try {
      annotations = summariseAnnotations(await gh(`/repos/${REPO}/check-runs/${run.id}/annotations`));
    } catch (err) {
      console.error(`check-ci: annotations for '${run.name}' failed: ${err.message}`);
    }
    out.push({
      name: run.name,
      conclusion: run.conclusion,
      url: run.html_url,
      title: run.output?.title || null,
      summary: (run.output?.summary || '').slice(0, 1500),
      annotations,
    });
  }
  return out;
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const publish = input?.steps?.publish || {};
  const prNumber = publish.prNumber;
  const branch = publish.branch;
  if (!prNumber) throw new Error('check-ci: no publish.prNumber in step input');

  const ciRound = Number(input?.steps?.['fix-after-tests']?.ciRound || 0);
  const prev = input?.steps?.['check-ci'];

  const pr = await gh(`/repos/${REPO}/pulls/${prNumber}`);
  const headSha = pr.head?.sha;
  if (!headSha) throw new Error(`check-ci: PR #${prNumber} has no head sha`);

  const checks = await gh(`/repos/${REPO}/commits/${headSha}/check-runs?per_page=100`);
  const runs = checks?.check_runs || [];
  const raw = classifyRuns(runs);

  // Consecutive-pending counter: bounds a stuck CI independently of fix rounds;
  // resets to 0 the moment CI produces a non-pending verdict.
  const pollCount = raw === 'pending'
    ? (prev?.raw === 'pending' ? Number(prev.pollCount || 1) + 1 : 1)
    : 0;

  const nextAction = decideNextAction(raw, ciRound, pollCount, CI_FIX_MAX, CI_POLL_MAX);
  const failing = raw === 'failed' ? await collectFailing(runs) : [];

  let reason;
  if (raw === 'passed') reason = `all ${runs.length} check(s) passed`;
  else if (raw === 'failed') reason = `${failing.map((f) => f.name).join(', ')} failed (round ${ciRound}/${CI_FIX_MAX})`;
  else reason = `CI still running (poll ${pollCount}/${CI_POLL_MAX})`;

  const giveupReason = nextAction === 'giveup'
    ? (raw === 'failed'
      ? `auto-fix exhausted after ${CI_FIX_MAX} round(s); still failing: ${failing.map((f) => f.name).join(', ')}`
      : `CI never completed after ${CI_POLL_MAX} poll(s)`)
    : null;

  writeFileSync('/output/result.json', JSON.stringify({
    prNumber, branch, headSha, raw, nextAction, ciRound, pollCount, failing, reason, giveupReason,
  }));
  console.log(`check-ci: PR #${prNumber} ${raw} -> ${nextAction} (${reason})`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('check-ci crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// mark-ci-green — CI passed on the PR; acknowledge it and record the fix history.
//
// Reached when `check-ci` routes `green`. Posts a "CI green" comment on the PR
// and, if the loop had to fix anything, appends a "CI fix history" section to
// the PR body so a human reviewer sees what the bot chased. Does NOT touch the
// draft flag: `publish` only drafts on capped-revise (unresolved review
// blockers), and a green CI does not resolve those — un-drafting is a human call.
//
// Reads:  /output/input.json (steps.publish, steps.fix-after-tests, steps.check-ci),
//         env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const HISTORY_MARKER = '### 🔁 CI fix history';

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok) throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  return res.status === 204 ? null : res.json();
}

/** Append a CI-fix-history section to an existing PR body. Idempotent (skips if
 *  already present) and a no-op when nothing was fixed. Pure. */
export function withFixHistory(body, ciFixLog) {
  if (!Array.isArray(ciFixLog) || ciFixLog.length === 0) return body;
  if ((body || '').includes(HISTORY_MARKER)) return body;
  const section = `${HISTORY_MARKER}\n${ciFixLog.map((l) => `- ${l}`).join('\n')}`;
  return `${body || ''}\n\n${section}`;
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const prNumber = input?.steps?.publish?.prNumber;
  const ciFixLog = input?.steps?.['fix-after-tests']?.ciFixLog;
  if (!prNumber) throw new Error('mark-ci-green: no publish.prNumber');

  const pr = await gh(`/repos/${REPO}/pulls/${prNumber}`);
  const newBody = withFixHistory(pr.body || '', ciFixLog);
  if (newBody !== (pr.body || '')) {
    await gh(`/repos/${REPO}/pulls/${prNumber}`, {
      method: 'PATCH',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: newBody }),
    });
  }

  await gh(`/repos/${REPO}/issues/${prNumber}/comments`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ body: '🤖 **mediforce-fullstack**: CI is green ✅ — ready for review.' }),
  }).catch((err) => console.error(`mark-ci-green: comment failed: ${err.message}`));

  writeFileSync('/output/result.json', JSON.stringify({ prNumber, ciGreen: true }));
  console.log(`mark-ci-green: PR #${prNumber} CI green`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('mark-ci-green crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// mark-ci-failed — CI is red (or stuck) and the auto-fix budget is spent; hand
// the PR to a human.
//
// Reached when `check-ci` routes `giveup`. Converts the PR to draft (so it is
// not merged with red CI), appends the CI fix history + the failing-check
// summary to the PR body, labels the issue `fullstack:ci-failing` for
// visibility, and comments what a human needs to pick up. Keeps `fullstack:pr-open`
// (the PR does exist). Best-effort throughout: a failed write leaves the red PR
// as its own signal.
//
// Converting an OPEN PR to draft is not a REST PATCH field — it needs the
// GraphQL `convertPullRequestToDraft` mutation, done here best-effort.
//
// Reads:  /output/input.json (steps.publish, steps.check-ci, steps.fix-after-tests),
//         env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const CI_FAILING = 'fullstack:ci-failing';
const HISTORY_MARKER = '### 🔁 CI fix history';
const FAILING_MARKER = '### ❌ CI failing — needs a human';

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

async function graphql(query, variables) {
  const res = await fetch('https://api.github.com/graphql', {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ query, variables }),
  });
  if (!res.ok) throw new Error(`GitHub GraphQL ${res.status}: ${(await res.text()).slice(0, 200)}`);
  const json = await res.json();
  if (json.errors) throw new Error(`GitHub GraphQL: ${JSON.stringify(json.errors).slice(0, 200)}`);
  return json.data;
}

/** Append the CI-fix-history + failing-check summary to a PR body. Idempotent,
 *  marker-guarded. Pure. */
export function buildFailedBody(body, ciFixLog, failing, giveupReason) {
  let out = body || '';
  if (Array.isArray(ciFixLog) && ciFixLog.length > 0 && !out.includes(HISTORY_MARKER)) {
    out += `\n\n${HISTORY_MARKER}\n${ciFixLog.map((l) => `- ${l}`).join('\n')}`;
  }
  if (!out.includes(FAILING_MARKER)) {
    const checks = (failing || []).map((f) => `- \`${f.name}\` — ${f.url}`).join('\n') || '- (see the Checks tab)';
    out += `\n\n${FAILING_MARKER}\n${giveupReason || 'CI did not go green.'}\n\n${checks}`;
  }
  return out;
}

export function failedComment(giveupReason, failing) {
  const checks = (failing || []).map((f) => `\`${f.name}\``).join(', ') || 'the failing checks';
  return `🤖 **mediforce-fullstack**: I could not get CI green here — ${giveupReason || 'it stayed red'}. ` +
    `Converted to draft and leaving it for a human; the failing checks are ${checks}. ` +
    'Push a fix (or `/code-review` it) and mark ready when it passes.';
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const publish = input?.steps?.publish || {};
  const check = input?.steps?.['check-ci'] || {};
  const ciFixLog = input?.steps?.['fix-after-tests']?.ciFixLog;
  const prNumber = publish.prNumber;
  const issueNumber = publish.issueNumber;
  if (!prNumber) throw new Error('mark-ci-failed: no publish.prNumber');

  try {
    const pr = await gh(`/repos/${REPO}/pulls/${prNumber}`);

    if (pr.draft !== true && pr.node_id) {
      await graphql(
        'mutation($id:ID!){convertPullRequestToDraft(input:{pullRequestId:$id}){pullRequest{isDraft}}}',
        { id: pr.node_id },
      ).catch((err) => console.error(`mark-ci-failed: draft conversion failed: ${err.message}`));
    }

    const newBody = buildFailedBody(pr.body || '', ciFixLog, check.failing, check.giveupReason);
    if (newBody !== (pr.body || '')) {
      await gh(`/repos/${REPO}/pulls/${prNumber}`, {
        method: 'PATCH',
        headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
        body: JSON.stringify({ body: newBody }),
      });
    }

    if (issueNumber) {
      await gh(`/repos/${REPO}/issues/${issueNumber}/labels`, {
        method: 'POST',
        headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
        body: JSON.stringify({ labels: [CI_FAILING] }),
      });
    }

    await gh(`/repos/${REPO}/issues/${prNumber}/comments`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: failedComment(check.giveupReason, check.failing) }),
    });
  } catch (err) {
    console.error(`mark-ci-failed: best-effort failure on PR #${prNumber}: ${err.message}`);
  }

  writeFileSync('/output/result.json', JSON.stringify({ prNumber, issueNumber, ciFailed: true, reason: check.giveupReason || null }));
  console.log(`mark-ci-failed: PR #${prNumber} handed to a human`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('mark-ci-failed crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// mark-fixed — the issue was already resolved by other changes; close it.
//
// Reached when `implement` reports changed=false, reason="already-fixed" with
// evidence. Posts the evidence, closes the issue (reversible — a human reopens
// if wrong), and drops the lease.
//
// Reads:  /output/input.json (steps.implement), env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const IN_PROGRESS = 'fullstack:in-progress';

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

export function fixedComment(evidence) {
  return `🤖 **mediforce-fullstack**: this looks already resolved${evidence ? ` by ${evidence}` : ''} — closing. ` +
    'Reopen if I\'ve got it wrong.';
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const impl = input?.steps?.implement || {};
  const issueNumber = impl.issueNumber;
  if (!issueNumber) throw new Error('mark-fixed: no implement.issueNumber');

  await gh(`/repos/${REPO}/issues/${issueNumber}/comments`, {
    method: 'POST',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ body: fixedComment(impl.evidence) }),
  });
  await gh(`/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(IN_PROGRESS)}`, { method: 'DELETE' });
  await gh(`/repos/${REPO}/issues/${issueNumber}`, {
    method: 'PATCH',
    headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
    body: JSON.stringify({ state: 'closed', state_reason: 'completed' }),
  });

  writeFileSync('/output/result.json', JSON.stringify({ issueNumber, closed: true }));
  console.log(`mark-fixed: closed #${issueNumber} (already fixed)`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('mark-fixed crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}

// mark-needs-info — park an issue for a human.
//
// Reached from two places:
//   - the gate `reject` verdict (human declined the plan)
//   - `implement` bailing (changed=false, reason="confused"/"broken")
// Swaps the working labels for `fullstack:needs-info` and comments why.
// Best-effort: a failed write just leaves the lease to expire and be reclaimed.
//
// Reads:  /output/input.json (steps.select / steps.implement / steps.clarify-approve),
//         env GITHUB_TOKEN, FULLSTACK_REPO
// Writes: /output/result.json

import { readFileSync, writeFileSync } from 'node:fs';

const REPO = process.env.FULLSTACK_REPO || 'Appsilon/mediforce';
const NEEDS_INFO = 'fullstack:needs-info';
const DROP = ['fullstack:in-progress', 'fullstack:awaiting-human'];

function ghHeaders() {
  const h = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
  if (process.env.GITHUB_TOKEN) h.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  return h;
}

async function gh(path, init) {
  const res = await fetch(`https://api.github.com${path}`, { headers: ghHeaders(), ...init });
  if (!res.ok && !(init?.method === 'DELETE' && res.status === 404)) {
    throw new Error(`GitHub ${res.status} ${init?.method || 'GET'} ${path}: ${(await res.text()).slice(0, 200)}`);
  }
  return res.status === 204 || res.status === 404 ? null : res.json();
}

export function resolveIssueNumber(input) {
  const s = input?.steps || {};
  return s.implement?.issueNumber ?? s.select?.issueNumber ?? null;
}

export function parkComment(input) {
  const s = input?.steps || {};
  const reason = s.implement?.summary || s['clarify-approve']?.guidance;
  return `🤖 **mediforce-fullstack**: parking this pending clarification${reason ? ` — ${reason}` : ''}. ` +
    'Leaving it to a human for now.';
}

async function main() {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf-8'));
  const issueNumber = resolveIssueNumber(input);
  if (!issueNumber) throw new Error('mark-needs-info: no issue number in step input');

  try {
    await gh(`/repos/${REPO}/issues/${issueNumber}/labels`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ labels: [NEEDS_INFO] }),
    });
    for (const name of DROP) {
      await gh(`/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(name)}`, { method: 'DELETE' });
    }
    await gh(`/repos/${REPO}/issues/${issueNumber}/comments`, {
      method: 'POST',
      headers: { ...ghHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ body: parkComment(input) }),
    });
  } catch (err) {
    console.error(`mark-needs-info: best-effort failure on #${issueNumber}: ${err.message}`);
  }

  writeFileSync('/output/result.json', JSON.stringify({ issueNumber, parked: true }));
  console.log(`mark-needs-info: parked #${issueNumber}`);
}

if (process.argv[1] && import.meta.url === `file://${process.argv[1]}`) {
  main().catch((err) => {
    console.error('mark-needs-info crashed:', err && err.stack ? err.stack : String(err));
    process.exit(1);
  });
}
